function getDefaultRetryText(manualMode) {
  return manualMode ? translate8(
    "After selecting a lorebook, try again.",
    "STMemoryBooks_RetryAfterManualLorebookSelection"
  ) : translate8(
    "After selecting a lorebook in SillyTavern, try again.",
    "STMemoryBooks_RetryAfterChatLorebookSelection"
  );
}
function getProblemText({ manualMode, lorebookName, reason }) {
  const escapedName = lorebookName ? escapeHtml(lorebookName) : "";
  if (reason === "unassigned") {
    return manualMode ? translate8(
      "No manual lorebook is currently selected for this chat.",
      "STMemoryBooks_NoManualLorebookSelected"
    ) : translate8(
      "No chat-bound lorebook is currently selected.",
      "STMemoryBooks_NoChatLorebookSelected"
    );
  }
  if (reason === "loadFailed") {
    return manualMode ? translate8(
      `The configured manual lorebook "${escapedName}" could not be loaded.`,
      "STMemoryBooks_ManualLorebookLoadFailedMessage"
    ) : translate8(
      `The chat-bound lorebook "${escapedName}" could not be loaded.`,
      "STMemoryBooks_ChatLorebookLoadFailedMessage"
    );
  }
  return manualMode ? translate8(
    `The configured manual lorebook "${escapedName}" was not found.`,
    "STMemoryBooks_ManualLorebookMissingMessage"
  ) : translate8(
    `The chat-bound lorebook "${escapedName}" was not found.`,
    "STMemoryBooks_ChatLorebookMissingMessage"
  );
}
function getActionText({ manualMode, allowCreate, hasExistingLorebooks }) {
  if (allowCreate && hasExistingLorebooks) {
    return translate8(
      "Create a replacement lorebook or select an existing one, then try again.",
      "STMemoryBooks_CreateOrSelectChatLorebookThenRetry"
    );
  }
  if (allowCreate) {
    return translate8(
      "Create a new lorebook to continue.",
      "STMemoryBooks_CreateLorebookToContinue"
    );
  }
  if (hasExistingLorebooks) {
    return manualMode ? translate8(
      "Select an existing lorebook for this chat, then try again.",
      "STMemoryBooks_SelectManualLorebookThenRetry"
    ) : translate8(
      "Select an existing lorebook in SillyTavern, then try again.",
      "STMemoryBooks_SelectChatLorebookThenRetry"
    );
  }
  return translate8(
    "No existing lorebooks are available to select.",
    "STMemoryBooks_NoExistingLorebooksAvailable"
  );
}
async function showLorebookRecoveryPopup({
  manualMode,
  lorebookName,
  allowCreate,
  createContext,
  retryText,
  reason
}) {
  const hasExistingLorebooks = Array.isArray(world_names4) && world_names4.length > 0;
  const title = translate8(
    "Memory Lorebook Missing",
    "STMemoryBooks_MemoryLorebookMissingTitle"
  );
  const popupContent = DOMPurify.sanitize(`
    <h4>${title}</h4>
    <div class="world_entry_form_control">
      <p>${getProblemText({ manualMode, lorebookName, reason })}</p>
      <p>${getActionText({ manualMode, allowCreate, hasExistingLorebooks })}</p>
      ${hasExistingLorebooks ? `<p>${retryText}</p>` : ""}
    </div>
  `);
  const customButtons = [];
  if (allowCreate) {
    customButtons.push({
      text: translate8(
        "Create New Lorebook",
        "STMemoryBooks_CreateNewLorebookButton"
      ),
      result: POPUP_RESULT2.CUSTOM1,
      appendAtEnd: true
    });
  }
  if (hasExistingLorebooks) {
    customButtons.push({
      text: translate8(
        "Select Existing Lorebook",
        "STMemoryBooks_SelectExistingLorebookButton"
      ),
      result: POPUP_RESULT2.CUSTOM2,
      appendAtEnd: true
    });
  }
  const recoveryPopup = new Popup2(popupContent, POPUP_TYPE2.TEXT, "", {
    okButton: false,
    cancelButton: translate8("Cancel", "STMemoryBooks_Cancel"),
    customButtons,
    leftAlign: true
  });
  markStmbPopup(recoveryPopup);
  const recoveryResult = await recoveryPopup.show();
  if (recoveryResult === POPUP_RESULT2.CUSTOM1 && allowCreate) {
    const template = extension_settings4?.STMemoryBooks?.moduleSettings?.lorebookNameTemplate || "LTM - {{char}} - {{chat}}";
    const createResult = await autoCreateLorebook(template, createContext);
    if (createResult.success) {
      return { type: "created", lorebookName: createResult.name };
    }
    return { type: "error", error: createResult.error };
  }
  if (recoveryResult === POPUP_RESULT2.CUSTOM2 && hasExistingLorebooks) {
    if (manualMode) {
      void showLorebookSelectionPopup(lorebookName).catch((error) => {
        console.error(
          "STMemoryBooks: Failed to open manual lorebook selection popup:",
          error
        );
      });
    } else {
      void assignLorebookToChat({ altKey: false }).catch((error) => {
        console.error(
          "STMemoryBooks: Failed to open chat lorebook selection popup:",
          error
        );
      });
    }
    return { type: "handled", error: retryText };
  }
  return {
    type: "handled",
    error: translate8(
      "Lorebook recovery cancelled.",
      "STMemoryBooks_LorebookRecoveryCancelled"
    )
  };
}
async function validateLorebookRequirement(options = {}) {
  const {
    skipAutoCreate = false,
    createContext = "chat",
    retryText = null,
    manualMode = void 0,
    lorebookName: lorebookNameOverride = void 0
  } = options;
  const settings = extension_settings4.STMemoryBooks;
  const resolvedManualMode = manualMode ?? !!settings?.moduleSettings?.manualModeEnabled;
  const allowCreate = !skipAutoCreate && !resolvedManualMode && !!settings?.moduleSettings?.autoCreateLorebook;
  const stmbData = resolvedManualMode ? getSceneMarkers() || {} : null;
  const resolvedRetryText = retryText || getDefaultRetryText(resolvedManualMode);
  let lorebookName = lorebookNameOverride !== void 0 ? lorebookNameOverride : resolvedManualMode ? stmbData?.manualLorebook ?? null : chat_metadata4?.[METADATA_KEY4] || null;
  let attempts = 0;
  while (attempts < 3) {
    let recoveryReason = null;
    if (!lorebookName) {
      recoveryReason = "unassigned";
    } else if (!world_names4 || !world_names4.includes(lorebookName)) {
      recoveryReason = "missing";
    }
    if (recoveryReason) {
      const recovery = await showLorebookRecoveryPopup({
        manualMode: resolvedManualMode,
        lorebookName,
        allowCreate,
        createContext,
        retryText: resolvedRetryText,
        reason: recoveryReason
      });
      if (recovery.type === "created") {
        lorebookName = recovery.lorebookName;
        attempts += 1;
        continue;
      }
      if (recovery.type === "error") {
        return { valid: false, error: recovery.error };
      }
      return { valid: false, error: recovery.error, handled: true };
    }
    try {
      const lorebookData = await loadWorldInfo3(lorebookName);
      if (!lorebookData) {
        throw new Error("Failed to load the selected lorebook.");
      }
      return { valid: true, data: lorebookData, name: lorebookName };
    } catch (error) {
      const recovery = await showLorebookRecoveryPopup({
        manualMode: resolvedManualMode,
        lorebookName,
        allowCreate,
        createContext,
        retryText: resolvedRetryText,
        reason: "loadFailed"
      });
      if (recovery.type === "created") {
        lorebookName = recovery.lorebookName;
        attempts += 1;
        continue;
      }
      if (recovery.type === "error") {
        return { valid: false, error: recovery.error };
      }
      return { valid: false, error: recovery.error, handled: true };
    }
  }
  return {
    valid: false,
    error: translate8(
      "Unable to resolve a valid lorebook.",
      "STMemoryBooks_UnableToResolveValidLorebook"
    )
  };
}

// autosummary.js
var autoSummarySkippedForProcessing = false;
var autoSummarySkippedMarkersRef = null;
function i18n3(key, fallback, params) {
  const localized = translate9(fallback, key);
  if (!params) return localized;
  return localized.replace(/{{\s*(\w+)\s*}}/g, (m, p1) => {
    const v = params[p1];
    return v !== void 0 && v !== null ? String(v) : "";
  });
}
async function validateLorebookForAutoSummary() {
  const settings = extension_settings5.STMemoryBooks;
  const manualMode = !!settings?.moduleSettings?.manualModeEnabled;
  if (manualMode) {
    const stmbData = getSceneMarkers() || {};
    let lorebookName = stmbData.manualLorebook ?? null;
    if (!lorebookName) {
      const popupContent = `
                <h4 data-i18n="STMemoryBooks_AutoSummaryReadyTitle">Auto-Summary Ready</h4>
                <div class="world_entry_form_control">
                    <p data-i18n="STMemoryBooks_AutoSummaryNoAssignedLorebook">Auto-summary is enabled but there is no assigned lorebook for this chat.</p>
                    <p data-i18n="STMemoryBooks_AutoSummarySelectOrPostponeQuestion">Would you like to select a lorebook for memory storage, or postpone this auto-summary?</p>
                    <label for="stmb-postpone-messages" data-i18n="STMemoryBooks_PostponeLabel">Postpone for how many messages?</label>
                    <select id="stmb-postpone-messages" class="text_pole">
                        <option value="10" data-i18n="STMemoryBooks_Postpone10">10 messages</option>
                        <option value="20" data-i18n="STMemoryBooks_Postpone20">20 messages</option>
                        <option value="30" data-i18n="STMemoryBooks_Postpone30">30 messages</option>
                        <option value="40" data-i18n="STMemoryBooks_Postpone40">40 messages</option>
                        <option value="50" data-i18n="STMemoryBooks_Postpone50">50 messages</option>
                    </select>
                </div>
            `;
      const popup = new Popup3(popupContent, POPUP_TYPE3.TEXT, "", {
        okButton: i18n3("STMemoryBooks_Button_SelectLorebook", "Select Lorebook"),
        cancelButton: i18n3("STMemoryBooks_Button_Postpone", "Postpone")
      });
      const result = await popup.show();
      if (result === POPUP_RESULT3.AFFIRMATIVE) {
        const selectedLorebook = await showLorebookSelectionPopup();
        if (selectedLorebook) {
          stmbData.manualLorebook = selectedLorebook;
          saveMetadataForCurrentContext();
          lorebookName = selectedLorebook;
        } else {
          return { valid: false, error: i18n3("STMemoryBooks_Error_NoLorebookSelectedForAutoSummary", "No lorebook selected for auto-summary.") };
        }
      } else {
        const postponeSelect = popup.dlg.querySelector("#stmb-postpone-messages");
        const parsed = parseInt(postponeSelect.value, 10);
        const postponeMessages = Number.isFinite(parsed) ? parsed : 10;
        const currentMessageCount = chat3.length;
        stmbData.autoSummaryNextPromptAt = currentMessageCount + postponeMessages;
        saveMetadataForCurrentContext();
        console.log(i18n3("autosummary.log.postponed", "STMemoryBooks: Auto-summary postponed for {{count}} messages (until message {{until}})", { count: postponeMessages, until: stmbData.autoSummaryNextPromptAt }));
        return { valid: false, error: i18n3("STMemoryBooks_Info_AutoSummaryPostponed", "Auto-summary postponed for {{count}} messages.", { count: postponeMessages }) };
      }
    }
    return await validateLorebookRequirement({
      createContext: "auto-summary",
      manualMode: true,
      lorebookName,
      retryText: i18n3("STMemoryBooks_AutoSummaryRetryAfterSelection", "After selecting a lorebook, try again.")
    });
  }
  return await validateLorebookRequirement({
    createContext: "auto-summary",
    manualMode: false,
    lorebookName: chat_metadata5?.[METADATA_KEY5] || null,
    retryText: i18n3("STMemoryBooks_AutoSummaryRetryAfterSelection", "After selecting a lorebook, try again.")
  });
}
async function checkAutoSummaryTrigger() {
  try {
    const settings = extension_settings5.STMemoryBooks;
    if (!settings?.moduleSettings?.autoSummaryEnabled) {
      return;
    }
    const stmbData = getSceneMarkers() || {};
    const currentMessageCount = chat3.length;
    const currentLastMessage = currentMessageCount - 1;
    const requiredInterval = settings.moduleSettings.autoSummaryInterval;
    const rawBuf = settings?.moduleSettings?.autoSummaryBuffer;
    const buffer = clampInt(parseInt(rawBuf) || 0, 0, 50);
    const requiredTotal = requiredInterval + buffer;
    const rawHighestProcessed = stmbData.highestMemoryProcessed;
    const hasHighestProcessed = typeof rawHighestProcessed === "number" && Number.isFinite(rawHighestProcessed);
    const highestProcessed = hasHighestProcessed ? rawHighestProcessed : -1;
    if (isMemoryProcessing()) {
      autoSummarySkippedForProcessing = true;
      autoSummarySkippedMarkersRef = stmbData;
      console.log(i18n3("autosummary.log.skippedInProgress", "STMemoryBooks: Auto-summary skipped - memory creation in progress"));
      return;
    }
    let messagesSinceLastMemory;
    messagesSinceLastMemory = currentLastMessage - highestProcessed;
    if (!hasHighestProcessed) {
      console.log(i18n3("autosummary.log.noPrevious", "STMemoryBooks: No previous memories found - counting from start"));
    } else {
      console.log(i18n3("autosummary.log.sinceLast", "STMemoryBooks: Messages since last memory ({{highestProcessed}}): {{count}}", { highestProcessed, count: messagesSinceLastMemory }));
    }
    console.log(i18n3("autosummary.log.triggerCheck", "STMemoryBooks: Auto-summary trigger check: {{count}} >= {{required}}?", { count: messagesSinceLastMemory, required: requiredTotal }));
    if (messagesSinceLastMemory < requiredTotal) {
      console.log(i18n3("autosummary.log.notTriggered", "STMemoryBooks: Auto-summary not triggered - need {{needed}} more messages", { needed: requiredTotal - messagesSinceLastMemory }));
      return;
    }
    if (stmbData.autoSummaryNextPromptAt && currentMessageCount < stmbData.autoSummaryNextPromptAt) {
      console.log(i18n3("autosummary.log.postponedUntil", "STMemoryBooks: Auto-summary postponed until message {{until}}", { until: stmbData.autoSummaryNextPromptAt }));
      return;
    }
    const lorebookValidation = await validateLorebookForAutoSummary();
    if (!lorebookValidation.valid) {
      console.log(i18n3("autosummary.log.blocked", "STMemoryBooks: Auto-summary blocked - lorebook validation failed: {{error}}", { error: lorebookValidation.error }));
      return;
    }
    if (stmbData.autoSummaryNextPromptAt) {
      delete stmbData.autoSummaryNextPromptAt;
      saveMetadataForCurrentContext();
      console.log(i18n3("autosummary.log.clearedPostpone", "STMemoryBooks: Cleared auto-summary postpone flag"));
    }
    let sceneStart, sceneEnd;
    const sceneEndCandidate = currentLastMessage - buffer;
    const safeEnd = Math.max(0, sceneEndCandidate);
    sceneStart = highestProcessed + 1;
    sceneEnd = safeEnd;
    if (sceneStart > sceneEnd) {
      return;
    }
    console.log(i18n3("autosummary.log.triggered", "STMemoryBooks: Auto-summary triggered - creating memory for range {{start}}-{{end}}", { start: sceneStart, end: sceneEnd }));
    stmbData.sceneStart = sceneStart;
    stmbData.sceneEnd = sceneEnd;
    saveMetadataForCurrentContext();
    const { executeSlashCommands: executeSlashCommands4 } = await import("../../../slash-commands.js");
    await executeSlashCommands4("/creatememory");
  } catch (error) {
    console.error(i18n3("autosummary.log.triggerError", "STMemoryBooks: Error in auto-summary trigger check:"), error);
  }
}
async function handleAutoSummaryMessageReceived() {
  try {
    if (extension_settings5.STMemoryBooks?.moduleSettings?.autoSummaryEnabled) {
      const currentMessageCount = chat3.length;
      console.log(i18n3("autosummary.log.messageReceivedSingle", "STMemoryBooks: Message received - auto-summary enabled, current count: {{count}}", { count: currentMessageCount }));
      await checkAutoSummaryTrigger();
    }
  } catch (error) {
    console.error(i18n3("autosummary.log.messageHandlerError", "STMemoryBooks: Error in auto-summary message received handler:"), error);
  }
}
async function retryAutoSummaryAfterJobIdle() {
  if (!autoSummarySkippedForProcessing) {
    return;
  }
  if (isMemoryProcessing()) {
    return;
  }
  if (autoSummarySkippedMarkersRef && autoSummarySkippedMarkersRef !== getSceneMarkers()) {
    autoSummarySkippedForProcessing = false;
    autoSummarySkippedMarkersRef = null;
    return;
  }
  autoSummarySkippedForProcessing = false;
  autoSummarySkippedMarkersRef = null;
  await checkAutoSummaryTrigger();
}
function clearAutoSummaryState() {
  if (extension_settings5.STMemoryBooks?.moduleSettings?.autoSummaryEnabled) {
    clearScene();
  }
}

