function getChatCompletionPresetOptions(selectedPreset = "") {
  const selected = String(selectedPreset || "").trim();
  const options = [{
    value: "",
    displayName: translate10("No Chat Completion preset", "STMemoryBooks_NoChatCompletionPreset"),
    selected: !selected
  }];
  try {
    const manager = getPresetManager("openai");
    const presetList = manager?.getPresetList?.("openai");
    const names = Array.isArray(presetList?.preset_names) ? presetList.preset_names : Object.keys(presetList?.preset_names || {});
    for (const name of names) {
      const value = String(name || "").trim();
      if (!value) continue;
      options.push({
        value,
        displayName: value,
        selected: value === selected
      });
    }
  } catch (error) {
    console.warn(`${MODULE_NAME6}: Failed to load Chat Completion presets`, error);
  }
  if (selected && !options.some((option) => option.value === selected)) {
    options.push({
      value: selected,
      displayName: selected,
      selected: true
    });
  }
  return options;
}
