async function deleteProfile(settings, profileIndex, refreshCallback) {
  if (settings.profiles.length <= 1) {
    toastr.error(translate10("Cannot delete the last profile", "STMemoryBooks_CannotDeleteLastProfile"), "STMemoryBooks");
    return;
  }
  const profile = settings.profiles[profileIndex];
  if (profile?.isBuiltinCurrentST) {
    toastr.error(translate10('Cannot delete the "Current SillyTavern Settings" profile - it is required for the extension to work', "STMemoryBooks_CannotDeleteDefaultProfile"), "STMemoryBooks");
    return;
  }
  try {
    const confirmText = translate10('Delete profile "{{name}}"?', "STMemoryBooks_DeleteProfileConfirm").replace("{{name}}", profile.name);
    const result = await new Popup4(confirmText, POPUP_TYPE4.CONFIRM, "").show();
    if (result === POPUP_RESULT4.AFFIRMATIVE) {
      const deletedName = profile.name;
      settings.profiles.splice(profileIndex, 1);
      if (settings.defaultProfile === profileIndex) {
        settings.defaultProfile = 0;
      } else if (settings.defaultProfile > profileIndex) {
        settings.defaultProfile--;
      }
      saveSettingsDebounced();
      if (refreshCallback) refreshCallback();
      toastr.success(translate10("Profile deleted successfully", "STMemoryBooks_ProfileDeletedSuccess"), "STMemoryBooks");
    }
  } catch (error) {
    console.error(`${MODULE_NAME6}: Error deleting profile:`, error);
    toastr.error(translate10("Failed to delete profile", "STMemoryBooks_FailedToDeleteProfile"), "STMemoryBooks");
  }
}
function exportProfiles(settings) {
  try {
    const exportData = {
      profiles: settings.profiles,
      exportDate: moment2().toISOString(),
      version: 1,
      moduleVersion: settings.migrationVersion || 1
    };
    const dataStr = JSON.stringify(exportData, null, 2);
    const dataBlob = new Blob([dataStr], { type: "application/json" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(dataBlob);
    link.download = `stmemorybooks-profiles-${moment2().format("YYYY-MM-DD")}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setTimeout(() => URL.revokeObjectURL(link.href), 1e3);
    toastr.success(translate10("Profiles exported successfully", "STMemoryBooks_ProfilesExportedSuccess"), "STMemoryBooks");
  } catch (error) {
    console.error(`${MODULE_NAME6}: Error exporting profiles:`, error);
    toastr.error(translate10("Failed to export profiles", "STMemoryBooks_FailedToExportProfiles"), "STMemoryBooks");
  }
}
function cleanProfile(profile) {
  return createProfileObject(profile);
}
function importProfiles(event, settings, refreshCallback) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    try {
      const importData = JSON.parse(e.target.result);
      if (!importData.profiles || !Array.isArray(importData.profiles)) {
        throw new Error(translate10("Invalid profile data format - missing profiles array", "STMemoryBooks_ImportErrorInvalidFormat"));
      }
      const validProfiles = importData.profiles.filter((profile) => validateProfile(profile)).map((profile) => cleanProfile(profile));
      if (validProfiles.length === 0) {
        throw new Error(translate10("No valid profiles found in import file", "STMemoryBooks_ImportErrorNoValidProfiles"));
      }
      let importedCount = 0;
      let skippedCount = 0;
      const existingNames = settings.profiles.map((p) => p.name);
      validProfiles.forEach((importProfile) => {
        const exists = existingNames.includes(importProfile.name);
        if (!exists) {
          const finalName = generateSafeProfileName(importProfile.name, existingNames);
          importProfile.name = finalName;
          existingNames.push(finalName);
          settings.profiles.push(importProfile);
          importedCount++;
        } else {
          skippedCount++;
        }
      });
      if (importedCount > 0) {
        saveSettingsDebounced();
        if (refreshCallback) refreshCallback();
        let message = __st_t_tag3`Imported ${importedCount} profile${importedCount === 1 ? "" : "s"}`;
        if (skippedCount > 0) {
          message += __st_t_tag3` (${skippedCount} duplicate${skippedCount === 1 ? "" : "s"} skipped)`;
        }
        toastr.success(message, translate10("STMemoryBooks profile import completed", "STMemoryBooks_ImportComplete"));
      } else {
        toastr.warning(translate10("No new profiles imported - all profiles already exist", "STMemoryBooks_ImportNoNewProfiles"), "STMemoryBooks");
      }
    } catch (error) {
      console.error(`${MODULE_NAME6}: Error importing profiles:`, error);
      toastr.error(__st_t_tag3`Failed to import profiles: ${error.message}`, "STMemoryBooks");
    }
  };
  reader.onerror = function() {
    console.error(`${MODULE_NAME6}: Error reading import file`);
    toastr.error(translate10("Failed to read import file", "STMemoryBooks_ImportReadError"), "STMemoryBooks");
  };
  reader.readAsText(file);
  event.target.value = "";
}
async function getLorebookEntriesForPicker(lorebookName) {
  const data = await loadWorldInfo4(lorebookName);
  return Object.entries(data?.entries || {}).map(([key, entry]) => ({
    uid: String(entry?.uid ?? key),
    title: getLorebookEntryDisplayName(entry, key)
  })).sort((a, b) => a.title.localeCompare(b.title));
}
