  const keywords = parseKeywords(dlg.querySelector("#stmb-clip-keywords")?.value || "");
  if (activation === "keyword" && keywords.length === 0) {
    throw new Error(tr3("STMemoryBooks_Clip_ErrorKeywordsRequired", "Keyword-activated clip entries require at least one keyword."));
  }
  if (!await showLongEntryWarning(lorebookName, lorebookData, null, content)) {
    return false;
  }
  const newEntry = createWorldInfoEntry2(lorebookName, lorebookData);
