function pluralizeSummaryLabel(label) {
  const raw = String(label || "").trim();
  if (!raw) return "Entries";
  if (/series$/i.test(raw)) return raw;
  if (/memory$/i.test(raw)) return `${raw.slice(0, -1)}ies`;
  if (/y$/i.test(raw)) return `${raw.slice(0, -1)}ies`;
  return `${raw}s`;
}
function normalizeAutoConsolidationTargetTiers(value, options = {}) {
  const fallback = Array.isArray(options?.fallback) ? options.fallback : [1];
  if (value === void 0 || value === null) {
    return [...fallback];
  }
  const isExplicitCollection = Array.isArray(value) || typeof value === "string";
  const rawValues = Array.isArray(value) ? value : typeof value === "string" ? value.split(/[,\s]+/g) : [value];
  const normalized = Array.from(
    new Set(
      rawValues.map((item) => Number(item)).filter((item) => Number.isFinite(item)).map((item) => clampInt(Math.trunc(item), 1, 5)).filter((item) => item >= 1 && item <= 5)
    )
  ).sort((a, b) => a - b);
  if (normalized.length) {
    return normalized;
  }
  return isExplicitCollection ? [] : [...fallback];
}
